inserted AS (
  INSERT INTO public.drills (
    name, module, sport, description, ai_context,
    progression_level, difficulty_levels, premium,
    is_active, is_published, instructions, subscription_tier_required
  )
  SELECT
    s.name,
    CASE WHEN 'PFP' = ANY(s.positions) THEN 'throwing' ELSE 'fielding' END,
    s.sport,
    s.description,
    s.ai_context,
    s.level,
    ARRAY['intermediate','advanced'],
    true, true, true,
    s.instructions,
    'premium'
  FROM seed s
  WHERE NOT EXISTS (
    SELECT 1 FROM public.drills d WHERE d.name = s.name AND d.sport = s.sport
  )
  RETURNING id, name, sport
),
pos_ins AS (
  INSERT INTO public.drill_positions (drill_id, position)
  SELECT i.id, unnest(s.positions)
  FROM inserted i JOIN seed s ON s.name=i.name AND s.sport=i.sport
  ON CONFLICT (drill_id, position) DO NOTHING
  RETURNING drill_id
),
tag_ins AS (
  INSERT INTO public.drill_tag_map (drill_id, tag_id, weight)
  SELECT i.id, dt.id, 1
  FROM inserted i
  JOIN seed s ON s.name=i.name AND s.sport=i.sport
  CROSS JOIN LATERAL unnest(s.tag_names) AS tn(tag_name)
  JOIN public.drill_tags dt ON dt.name = tn.tag_name
  ON CONFLICT (drill_id, tag_id) DO NOTHING
  RETURNING drill_id
)
SELECT count(*) AS drills_inserted FROM inserted;
